package com.hospital.management.controller.appointment;import com.hospital.management.model.Appointment;import com.hospital.management.service.*;import com.hospital.management.service.impl.*;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/appointments/view")public class AppointmentViewServlet extends HttpServlet {private final AppointmentService service;private final MedicalRecordService records;private final BillService bills;public AppointmentViewServlet(){this(new AppointmentServiceImpl(),new MedicalRecordServiceImpl(),new BillServiceImpl());}public AppointmentViewServlet(AppointmentService s){this(s,new MedicalRecordServiceImpl(),new BillServiceImpl());}public AppointmentViewServlet(AppointmentService s,MedicalRecordService m){this(s,m,new BillServiceImpl());}public AppointmentViewServlet(AppointmentService s,MedicalRecordService m,BillService b){service=s;records=m;bills=b;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AppointmentRequest.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Appointment a=service.getAppointment(id,AppointmentRequest.user(q)).orElse(null);if(a==null){r.sendError(404);return;}q.setAttribute("appointment",a);q.setAttribute("medicalRecord",records.getRecordByAppointment(id,AppointmentRequest.user(q)).orElse(null));q.setAttribute("bill",bills.getByAppointment(id,AppointmentRequest.user(q)).orElse(null));q.getRequestDispatcher("/WEB-INF/views/appointments/view.jsp").forward(q,r);}}
